 RNA-seq м „мІҳлҰ¬ #1 Quality control # #2026-01-25
#1 quality control
DHT м•Ҫл¬ј мІҳлҰ¬лҗң 18к°ң мғҳн”Ңмқҳ paired-end RNA-seq лҚ°мқҙн„°лҘј quality control мҲҳн–ү. FastQC лҸ„кө¬лҘј мӮ¬мҡ©н–Ҳкі  run_fastqc.sh мҠӨнҒ¬лҰҪнҠё л§Ңл“Өм–ҙм„ң мһ‘м—….
#!/bin/bash # input fastq directory FASTQ_DIR=&#34;../2306_tophat/data/Bowtie2Index&#34; # output directory OUT_DIR=&#34;FastQC&#34; # run fastqc mkdir -p &#34;${OUT_DIR}&#34; for fq in \ 5-AZA_150-*_edited.fastq \ 5-AZA_33-*.fastq \ 5-AZA_con-*.fastq do echo &#34;Running FastQC on ${fq}&#34; fastqc &#34;${FASTQ_DIR}/${fq}&#34; -o &#34;${OUT_DIR}&#34; done echo &#34;FastQC completed.&#34; chmod +x run_fastqc.sh ./run_fastqc.sh н’Ҳм§Ҳ л ҲнҸ¬нҠё нҷ•мқё кІ°кіј лӘЁл“  мғҳн”Ңм—җ кіөнҶөм ҒмңјлЎң read 5вҖҷ л§җлӢЁ 1-10bp кө¬к°„мқҳ м—јкё° мЎ°м„ұмқҙ к· мқјн•ҳм§Җ м•ҠмқҢ. м°ёкі  л…јл¬ём—җ л”°лқј 1-10bpм—җ atgcк°Җ м„ңм—ҙ лӮҙмҡ©мқҙ л¬ҙмһ‘мң„лЎң л¶„нҸ¬н•ҳлҠ” л¶Җл¶„мқ„ Trimming мһ‘м—…. trim_fastq.sh мҠӨнҒ¬лҰҪнҠё л§Ңл“Өм–ҙм„ң мһ‘м—…н•Ё.
#!/bin/bash set -euo pipefail # ===== м„Өм • ===== IN_DIR=&#34;../2306_tophat/data/Bowtie2Index&#34; OUT_DIR=&#34;./Trim&#34; S=10 E=0 mkdir -p &#34;${OUT_DIR}&#34; FASTQ_FILES=( &#34;${IN_DIR}&#34;/5-AZA_150-*.fastq &#34;${IN_DIR}&#34;/5-AZA_33-*.fastq &#34;${IN_DIR}&#34;/5-AZA_con-*.fastq ) echo &#34;[INFO] Trimming FASTQ files...&#34; for in_fq in &#34;${FASTQ_FILES[@]}&#34;; do [[ -f &#34;$in_fq&#34; ]] || continue base=&#34;$(basename &#34;$in_fq&#34;)&#34; out_fq=&#34;${OUT_DIR}/${base%.fastq}_trimmed.fastq&#34; echo &#34;[TRIM] $base -&gt; $(basename &#34;$out_fq&#34;)&#34; # ---- кё°мЎҙ awk лЎңм§Ғ к·ёлҢҖлЎң ---- awk -v s=&#34;${S}&#34; -v e=&#34;${E}&#34; &#39;{if (NR%2 == 0) print substr($0, s+1, length($0)-s-e); else print $0; }&#39; \ &#34;$in_fq&#34; &gt; &#34;$out_fq&#34; done echo &#34;[DONE] Trimming completed.&#34; chmod +x trim_fastq.sh ./trim_fastq.sh &gt; trim.log 2&gt;&amp;1 # #2 м •лҰ¬
18к°ң мғҳн”Ңмқҳ paired-end RNA-seq лҚ°мқҙн„°м—җ лҢҖн•ҙм„ң FastqcлҘј мӮ¬мҡ©н•ҙм„ң н’Ҳм§Ҳ нҸүк°ҖлҘј мҲҳн–ү. н’Ҳм§Ҳ л ҲнҸ¬нҠё кІ°кіјм—җ л”°лқј 5вҖІ л§җлӢЁ 10bp trimmingмқ„ мҲҳн–үн•ҳм—¬ alignment мһ…л Ҙ RNA-seqмқҳ мқјкҙҖм„ұмқ„ нҷ•ліҙн–ҲлӢӨ.

 ChIP-seq м „мІҳлҰ¬ (trimmomatic, samtools) # #2025-04-21
1. Trimming # chipseq_trimming.sh
#!/bin/bash # setting envs export bdir=&#34;/data3/projects/2022_KNU_EBV&#34; export hg38_bowtieidx=&#34;/data3/PUBLIC_DATA/ref_genomes/homo_sapiens/hg38/hg38_bowtie_idx/hg38.fa&#34; export hg38_bwaidx=&#34;/data3/PUBLIC_DATA/ref_genomes/homo_sapiens/hg38/hg38_bwa_index/hg38.fa&#34; export ebv_bowtie2idx=&#34;/data3/PUBLIC_DATA/ref_genomes/Human_gammaherpesvirus_4_EBV/EBV_bowtie2_idx/NC_007605.1.fa&#34; export ebv_bwaidx=&#34;/data3/PUBLIC_DATA/ref_genomes/Human_gammaherpesvirus_4_EBV/EBV_bwa_index/NC_007605.1.fa&#34; ### SET Path ### cd /data3/RAW_DATA/2023_KNU_EBV/ChIP-seq ### TRIMMING data ### mkdir -p trimmed sampdir=&#34;/data3/RAW_DATA/2023_KNU_EBV/ChIP-seq&#34; samplist=(&#34;Input&#34; &#34;p65&#34; &#34;RIgG&#34;) TRIMMOMATIC= &#34;/data/packages/trimmomatic/Trimmomatic-0.39/trimmomatic-0.39.jar&#34; for sampname in &#34;${samplist[@]}&#34;; do mkdir -p &#34;trimmed/${sampname}&#34; java -jar $TRIMMOMATIC PE -threads 40 -trimlog log1.txt $sampdir/${sampname}_1.fastq/${sampname}_1.fastq $sampdir/${sampname}_2.fastq/${sampname}_2.fastq $sampdir/trimmed/${sampname}/${sampname}_1.trimmed.fastq $sampdir/trimmed/${sampname}/${sampname}_1.up.trimmed.fastq $sampdir/trimmed/${sampname}/${sampname}_2.trimmed.fastq $sampdir/trimmed/${sampname}/${sampname}_2.up.trimmed.fastq ILLUMINACLIP:/data1/packages/trimmomatic/Trimmomatic-0.39/adapters/TruSeq3-PE.fa:2:30:10:2:True LEADING:3 TRAILING:3 MINLEN:36 done # 2. Alignment # chipseq_alignment.sh
#!/bin/bash # setting envs export bdir=&#34;/data3/projects/2022_KNU_EBV&#34; export hg38_bowtieidx=&#34;/data3/PUBLIC_DATA/ref_genomes/homo_sapiens/hg38/hg38_bowtie_idx/hg38.fa&#34; export hg38_bwaidx=&#34;/data3/PUBLIC_DATA/ref_genomes/homo_sapiens/hg38/hg38_bwa_index/hg38.fa&#34; export ebv_bowtie2idx=&#34;/data3/PUBLIC_DATA/ref_genomes/Human_gammaherpesvirus_4_EBV/EBV_bowtie2_idx/NC_007605.1.fa&#34; export ebv_bwaidx=&#34;/data3/PUBLIC_DATA/ref_genomes/Human_gammaherpesvirus_4_EBV/EBV_bwa_index/NC_007605.1.fa&#34; ### SET Path ### cd /data3/RAW_DATA/2023_KNU_EBV/ChIP-seq sampdir=&#34;/data3/RAW_DATA/2023_KNU_EBV/ChIP-seq&#34; samplist=(&#34;Input&#34; &#34;p65&#34; &#34;RIgG&#34;) for sampname in &#34;${samplist[@]}&#34;; do bwa mem -t 20 -v 2 $ebv_bwaidx $bdir/trimmed/CTCF-C-SNU719_1.trimmed.fastq $bdir/trimmed/CTCF-C-SNU719_2.trimmed.fastq &gt; $bdir/aln/bwa/CTCF-C_PE.bwa.sam done ### Aligning to EBV - PE bwa mem -t 20 -v 2 $ebv_bwaidx $bdir/trimmed/CTCF-C-SNU719_1.trimmed.fastq $bdir/trimmed/CTCF-C-SNU719_2.trimmed.fastq &gt; $bdir/aln/bwa/CTCF-C_PE.bwa.sam samtools view -hf 2 $bdir/aln/bwa/CTCF-C_PE.bwa.sam | samtools sort -o $bdir/aln/bwa/CTCF-C_PE.bwa.bam -O BAM -@ 20 - samtools index -@ 20 $bdir/aln/bwa/CTCF-C_PE.bwa.bam bamCoverage -b $bdir/aln/bwa/CTCF-C_PE.bwa.bam -o $bdir/aln/bwa/CTCF-C_PE.bwa.bam.bigwig macs2 callpeak -t $bdir/aln/bwa/CTCF-C_PE.bwa.bam -f BAMPE -n CTCF-C --outdir peaks_ebv ### @REF: hg38 bowtie2 -k1 --no-unal -p 40 --qc-filter -x $bowtie2idx_hg38 -1 $bdir/trimmed/CTCF-C-SNU719_1.trimmed.fastq -2 $bdir/trimmed/CTCF-C-SNU719_2.trimmed.fastq &gt; $bdir/aln/bwt2/CTCF-C_PE_hg38.sam &gt; $bdir/aln/bwt2/CTCF-C_PE_hg38.sam samtools view -hf 2 $bdir/aln/bwt2/CTCF-C_PE_hg38.sam | samtools sort -o $bdir/aln/bwt2/CTCF-C_PE_hg38.bam -O BAM -@ 20 - sambamba view -h -t 20 -f bam -p -F &#34;[XS] == null and not unmapped and not duplicate&#34; $bdir/aln/bwt2/CTCF-C_PE_hg38.bam &gt; $bdir/aln/bwt2/CTCF-C_PE_hg38_u.bam samtools index -@ 20 $bdir/aln/bwt2/CTCF-C_PE_hg38_u.bam macs2 callpeak -t $bdir/aln/bwt2/CTCF-C_PE_hg38_u.bam -f BAMPE -n CTCF-C --outdir peaks # 3. Peak Calling # bedgraph.sh
#!/bin/bash input_file=&#34;KEB01_1_bismark_bt2_pe.sorted.bedGraph.gz&#34; output_file=&#34;KEB01_1_bismark_bt2_pe.sorted_edited.bedGraph&#34; cd /data/home/ysh980101/2309_5-aza/Bismark_temp_GRCh38 zcat &#34;$input_file&#34; | awk &#39;$4 != 0 { $1 = &#34;chr&#34; $1; print }&#39; | gzip &gt; &#34;$output_file.gz&#34; #

 мӮҙл§Ңн•ңмқҙмң  # #2021-06-05 01:48:32
лӮҳлҠ”м§ҖкёҲмқҙ м ңмқјмўӢлӢӨ мўӢмқҖкұё лҠҗлҒјм§„лӘ»н•ҳлҠ”лҚ° мқҙм„ұм Ғ мӮ¬кі лҘјл”°лқјк°Җліҙл©ҙ мўӢмқҖкұё м•ҢмҲҳмһҲлӢӨ. мҳҲм „м—җ мӢ«м—ҲлҚҳкІғл“Ө м§ҖкёҲліҙл©ҙ кұ°мқҳлӢӨ мӮӯм ңлҸјмһҲкі  мҳҲм „м—җ к°–кі мӢ¶м—ҲлҚҳкІғл“Ө лӢӨлҠ” м•„лӢҲм–ҙлҸ„ мЎ°кёҲмқҖк°–м·„кі  к°–м¶”кі мӢ¶мқҖкІғ м•„м§Ғ лӮЁм•ҳкі &hellip;
кёёк°ҖлӢӨ м°Ҫм—җл№„м№ңлӘЁмҠө, л§Өмқјлҳ‘к°ҷмқҖлҚ°лҸ„ мӮ¬л¬ҙм№ҳлҠ” кі нҶө. лӮҙк°Җ нғңм–ҙлӮ л•Ңл¶Җн„° к°–м§ҖлӘ»н•ңкІғкіј к·ёкұёк°Җм§„лҲ„кө°к°ҖлҘј ліҙлҠ”лӮҳ к·ёлғҘ м„ёмғҒмҶҚм—җлҶ“мқё лӮҳлҘј мқём§Җн•ҳлҠ” кё°нғҖл“ұл“ұ мӮ¬мҶҢн•ңмғҒнҷ©мҶҚм—җм„ң лӮҳлҠ” мҶҢмҶҢнһҲ н•ҳм§Җл§Ң нҷ•мӢӨн•ңл¶Ҳн–үмқ„ лҠҗлӮҖлӢӨ. к·јлҚ° к·ёкІғл“Өмқҙ мһҲмқҢмқҙмҳӨнһҲл Ө м•Ҳм •к°җмңјлЎң лӢӨк°ҖмҳӨлӢҲк№Ңкҙңм°®лӢӨ мҷңлғҗл©ҙ кё°л¶„мқҙ м–ҙлҠҗм •лҸ„лЎң мң м§ҖлҗҳлҠ”м§Җ мқём§Җн•ҳкі мӮҙмҲҳмһҲлҠ”кІҢ мўӢкё°л•Ңл¬ёмқҙлӢӨ. м•Ҳм •к°җмқҖмўӢмқҖкІғмқҙлӢӨ мһ‘мқҖл¶Ҳн–үлҸ„ мһ‘мқҖн–үліөлҸ„ кІ°көӯмқҖмҳҲмёЎн• мҲҳмһҲкі  мҶҗм•Ҳм—җ мһҲлӢӨлҠ”кІҢ мӨ‘мҡ”н•ңкұ°лӢӨ лӯҗк°Җлҗҗл“ &hellip; лӮҙмҶҗм•Ҳм—җ мһҲлӢӨлҠ”кІҢ мқҳлҜёк°ҖмһҲлӢӨ

 м–ҙнңҙ # #2019-10-01 00:42:56
мҳӨлҠҳ 1к°ңмһҲлҠ” мҲҳм—…мқҙ нңҙк°•мқҙлқјм„ң кіөк°•мқёлӮ мқҙ лҗҸлӢӨ. мҳҲм „м—җ м№ңкө¬лһ‘ к°“лҚҳ мҠӨн„°л””м№ҙнҺҳ мғқк°ҒмқҙлӮҳм„ң кұ°кё°м„ң 6мӢңк°„ кіөл¶ҖлҘјн•ҳкі мҷ“лӢӨ. мҡ”мҰҳ 20л¶„мқҙмғҒ м§‘мӨ‘н•ңкё°м–өмқҙ м—ҶлҠ”лҚ° мҳӨлһңл§Ңм—җ кіөл¶ҖлҘј мҳӨлһҳн–ҮлӢӨ. м—„мІӯ л§Һмқҙн•ңкұҙ м•„лӢҲм§Җл§Ң&hellip;
мӢӨм»· кіөл¶Җ мһҳн•ҳкі мҷҖм„ң, м§‘м—җмҷҖм„ң м№ЁлҢҖм—җлҲ„мӣҢм„ң мң нҠңлёҢлҸ„ н•ңм°ёліҙкі м„ң, к°‘мһҗкё° мҡ°мҡён•ҙм ём„ң мҡ°мҡён•ҙн•ҳлӢӨк°Җ мһҗкё°м—°лҜјм—җл№ м ё м—үм—үмҡёлӢӨк°Җ мұ…мғҒм—җ м•үм•„ м§‘мӨ‘н•ҳл ӨлҠ”лҚ° м§‘мӨ‘мқҙм•ҲлҸјм„ң, мқҙлҹ° м§‘мӨ‘л Ҙкіј нғңлҸ„лЎң м–ҙл–»кІҢ кі мӢңк°ҷмқҖ мӢңн—ҳ мӨҖл№„лҘј н•ҳкІ лҠ”м§Җ, л¶ҲнҲ¬лӘ…н•ңм „л§қм—җ л§ҲмқҢмЎёмқҙл©° мҡёлӢӨк°Җ лӯ”к°Җ мӮҙм°җкІғк°ҷм•„м„ң мһҗкё°нҳҗмҳӨлҘј лҠҗлҒјлӢӨк°Җ, м •л§җмқҙм§Җ мқөмҲҷн•ҳкі  м§ҖкІЁмҡҙ мқјл Ёмқҳ мҡ°мҡёк°җмқҙм§Җл§Ң лӮҳлҠ” л§Ҳм№ҳ мІҳмқҢ мҡ°мҡён•ҙн•ҳлҠ”мӮ¬лһҢл§ҲлғҘ л№ м ёлӮҳмҳӨм§ҖлӘ»н•ҳкі  мҡ°мҡён•ҙн–ҲлӢӨлҠ”кІҢ м–ҙмқҙм—Ҷм–ҙм„ң лӮҳмӨ‘м—җ ліҙкі  н•ңмӢ¬н•ҙн•ҳлқјкі  м“°лҠ”мқјкё°
м–ҙм ңм Җл…Ғл¶Җн„° м•„м№Ёк№Ңм§Җл§Ңн•ҙлҸ„ л§ҲмқҢнҺён•ҳкІҢлЁ№кі  к·ёлғҘ мӮҙмһҗкі  мғқк°Ғл“Өм—ҮлҠ”лҚ° м–ём ңк·ёлһ¬лғҗлҠ”л“Ҝ мЎ°кёү+мһҗкё°м—°лҜј&amp;мһҗкё°нҳҗмҳӨмҪӨліҙ мӢңм „н•ҙлІ„лҰ¬л„Ө г…Ӣг…Ӣг…Ӣ г„№г…Үл…ёмқҙн•ҙ н•ҳм§Җл§Ң мқјкё°лҘјм“°л©ҙ л§Һмқҙ н•ҙмҶҢлҗЁ. л§Өмҡ° мғҒнҲ¬м Ғмқё л§Ҳл¬ҙлҰ¬лЎңкө° лӮңнҸүмғқк·ёлғҘ мқҙлҹ¬кі мӮҙл“Ҝ&hellip;

 мҠ¬лҰ¬н•‘лІ„мҠӨ # #2019-01-20 18:52:26
мҠ¬лҰ¬н•‘лІ„мҠӨлҘј мІҳмқҢнғҖлҙЈлҠ”лҚ° мўҖ мҠөн•ҳкі  мӮ¬лһҢлғ„мғҲ(кҙҖл…җм Ғмқёкұ° м•„лӢҲкі  нҷ”н•ҷм Ғ&rsquo;лғ„мғҲ&rsquo;)лӮңлӢӨлҠ”кұ° л§җкі лҠ” мўӢлӢӨ мһЎл…җмқҙ мӮ¬лқјм§ҖлҠ”кё°л¶„мһ„. мқҙлІҲм—¬н–үмҷҖм„ң м ңмқј л§Һмқҙмғқк°Ғн•ңкұ°лҠ” л°°л ӨмҷҖ мӢңлҜјмқҳмӢқмқёлҚ° нҠ№нһҲлӮҳ лӮҙк°Җ л°°л Өк°Җл§Һмқҙ л¶ҖмЎұн•Ёмқ„ лҠҗкјҮлӢӨ. лӮҙк°Җ мӨ‘лҰҪмқё мӮ¬м•Ҳм—җм„ң м„ нғқк¶Ңмқ„ лӮЁн•ңн…Ң л„ҳкІЁмЈјлҠ”кұҙ л°°л Өм—ҝлӢӨкё°ліҙлӢӨлҠ”&hellip; м•„лӢҢкІғлҸ„ м•„лӢҲм§Җл§Ң м• мҙҲм—җ мү¬мҡҙмқјмқҙм—Үкі  лӮҙк°Җ aлқјлҠ” мғқк°Ғмқ„ к°Җм§„ мӮ¬м•Ҳмқ„ лӮЁмқҙ л°ҳл°•н–Ҳмқ„л•Ң лӮҙк°Җ нӢҖл ёмқ„мҲҳмһҲлӢӨлҠ”л§ҲмқҢк°Җм§җмқ„ к°–лҠ”кұҙ м–ҙл өкі  н•„мҡ”н•ңл“Ҝ. лҚ”л¶Ҳм–ҙ л°ҳл°•лӢ№н–Ҳмқ„л•Ң л¶ҲмҫҢн•ҳм§Җм•ҠлҠ”кІғ&hellip;
лӮҙк°Җ мһҗмЈјн•ҳлҠ”л§җмӨ‘м—җ &lsquo;к·ёлһҳ м¶©л¶„нһҲ к·ёл ҮкІҢ мғқк°Ғн• мҲҳмһҲлӢӨ&rsquo; к°Җ мһҲлҠ”лҚ° мӮ¬мӢӨ лӮҳм—җкІҢмһҲм–ҙм„ң к·ёкұҙ лӮЁмқ„ мЎҙмӨ‘н•ҳлҠ”л§ҲмқҢм—җм„ң лӮҳмҳЁ л§җмқҙ м „нҳҖ м•„лӢҲкі  мҳӨнһҲл Ө лӮҙ к·ҖлҘјл§үм•„лІ„лҰјкіј лҸҷмӢңм—җ мғҒлҢҖмқҳ мһ…мқ„ л§үкі мӢ¶мқ„л•Ң м“°лҠ” л§җмқҙлӢӨ. к·ёлҰ¬кі  к·ёкІҢ м—„мІӯ л¬ҙлЎҖн•ңмқјмқҙм—ҲмқҢмқ„ к№ЁлӢ¬м•—мқҢ н•ңлІҲмқҙлқјлҸ„ мЎҙмӨ‘н•ҳлҠ” м–ён–үм—җ лҢҖн•ҙ мғқк°Ғн•ҙлҙЈлҚҳ мӮ¬лһҢмқҖ лӮҙк°Җ к·ёл ҮкІҢ л§җн–Ҳмқ„л•Ң м–јл§ҲлӮҳ к°ңл…җм—Ҷмқҙ л§җлұүлҠ”к°Җ мғқк°Ғн•ҳкі  мҶҚмңјлЎң нҳҖлҘј м°јкІ м§Җ&hellip; кІ°лЎ м ҒмңјлЎңлҠ” лӮЁмқ„ мЎҙмӨ‘н•ҳкі  л“Өмңјл Ө л…ёл Ҙн•ҳмһҗ(м •нҷ•нһҲлҠ” к·ё мғҒлҢҖлҘј мӣғм–ҙлҘёмңјлЎң көӯн•ңн•ҳм§Җл§җмһҗ)~~
